CREATE TABLE cybersecurity_tool_to_quant_metric
(
	id serial,
	cybersecurity_tool_id integer NOT NULL,
	quant_metric_id integer DEFAULT NULL,
	CONSTRAINT pk_cybersecurity_tool_to_quant_metric PRIMARY KEY (id)
	, CONSTRAINT fk_cybersecurity_tool_to_quant_metric_to_cybersecurity_tool FOREIGN KEY (cybersecurity_tool_id) REFERENCES cybersecurity_tools (id) MATCH SIMPLE ON UPDATE CASCADE ON DELETE CASCADE
	, CONSTRAINT fk_cybersecurity_tool_to_quant_metric_to_quant_metric FOREIGN KEY (quant_metric_id) REFERENCES quant_metrics (id) MATCH SIMPLE ON UPDATE CASCADE ON DELETE CASCADE
);
CREATE INDEX i_cybersecurity_tool_to_quant_metric_to_cybersecurity_tool ON cybersecurity_tool_to_quant_metric (cybersecurity_tool_id);
CREATE INDEX i_cybersecurity_tool_to_quant_metric_to_quant_metric ON cybersecurity_tool_to_quant_metric (quant_metric_id);
